PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE accounts (
  id TEXT PRIMARY KEY,
  email TEXT NOT NULL UNIQUE,
  name TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  consent_given_at TEXT NOT NULL,
  consent_version TEXT NOT NULL,
  last_login_at TEXT
, stripe_customer_id TEXT, subscription_status TEXT, subscription_current_period_end INTEGER, is_comped INTEGER NOT NULL DEFAULT 0, comp_source TEXT, email_opt_in INTEGER NOT NULL DEFAULT 0);
CREATE TABLE quiz_results (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  child_id TEXT NOT NULL REFERENCES children(id) ON DELETE CASCADE,
  topic_key TEXT NOT NULL,
  subject TEXT NOT NULL,
  score INTEGER NOT NULL,
  total INTEGER NOT NULL,
  time_seconds INTEGER,
  quiz_mode TEXT,
  completed_at TEXT NOT NULL DEFAULT (datetime('now'))
, session_id INTEGER);
CREATE TABLE mock_test_results (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  child_id TEXT NOT NULL REFERENCES children(id) ON DELETE CASCADE,
  subject TEXT NOT NULL,
  total_questions INTEGER NOT NULL,
  total_correct INTEGER NOT NULL,
  percentage INTEGER NOT NULL,
  time_taken INTEGER NOT NULL,
  time_limit INTEGER NOT NULL,
  section_results TEXT NOT NULL,
  question_times TEXT,
  completed_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE question_results (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  child_id TEXT NOT NULL REFERENCES children(id) ON DELETE CASCADE,
  question_id INTEGER NOT NULL,
  topic_key TEXT NOT NULL,
  subject TEXT NOT NULL,
  is_correct INTEGER NOT NULL,
  time_ms INTEGER,
  difficulty INTEGER,
  attempted_at TEXT NOT NULL DEFAULT (datetime('now'))
, session_id INTEGER, selected_answer TEXT);
CREATE TABLE lesson_history (
  child_id TEXT NOT NULL REFERENCES children(id) ON DELETE CASCADE,
  lesson_id TEXT NOT NULL,
  completed_at TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (child_id, lesson_id)
);
CREATE TABLE practice_sessions (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  child_id TEXT NOT NULL REFERENCES children(id) ON DELETE CASCADE,
  session_date TEXT NOT NULL,
  data TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  UNIQUE(child_id, session_date)
);
CREATE TABLE seen_questions (
  child_id TEXT NOT NULL REFERENCES children(id) ON DELETE CASCADE,
  question_id INTEGER NOT NULL,
  topic_key TEXT NOT NULL,
  subject TEXT NOT NULL,
  first_seen_at TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (child_id, question_id, topic_key)
);
CREATE TABLE achievements (
  child_id TEXT NOT NULL REFERENCES children(id) ON DELETE CASCADE,
  achievement_id TEXT NOT NULL,
  unlocked_at TEXT NOT NULL DEFAULT (datetime('now')), seen INTEGER NOT NULL DEFAULT 0,
  PRIMARY KEY (child_id, achievement_id)
);
CREATE TABLE seen_tips (
  child_id TEXT NOT NULL REFERENCES children(id) ON DELETE CASCADE,
  tip_id TEXT NOT NULL,
  last_seen_date TEXT NOT NULL,
  PRIMARY KEY (child_id, tip_id)
);
CREATE TABLE topic_performance (
  child_id TEXT NOT NULL REFERENCES children(id) ON DELETE CASCADE,
  topic_key TEXT NOT NULL,
  subject TEXT NOT NULL,
  data TEXT NOT NULL,
  version INTEGER NOT NULL DEFAULT 1,
  updated_at TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (child_id, topic_key, subject)
);
CREATE TABLE leitner_queue (
  child_id TEXT NOT NULL REFERENCES children(id) ON DELETE CASCADE,
  question_id INTEGER NOT NULL,
  topic_key TEXT NOT NULL,
  subject TEXT NOT NULL,
  level INTEGER NOT NULL DEFAULT 0,
  last_reviewed TEXT,
  next_review TEXT,
  times_correct INTEGER DEFAULT 0,
  times_incorrect INTEGER DEFAULT 0,
  PRIMARY KEY (child_id, question_id, topic_key)
);
CREATE TABLE streaks (
  child_id TEXT PRIMARY KEY REFERENCES children(id) ON DELETE CASCADE,
  current_streak INTEGER NOT NULL DEFAULT 0,
  longest_streak INTEGER NOT NULL DEFAULT 0,
  last_quiz_date TEXT,
  streak_history TEXT NOT NULL DEFAULT '[]',
  version INTEGER NOT NULL DEFAULT 1,
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE prep_points (
  child_id TEXT PRIMARY KEY REFERENCES children(id) ON DELETE CASCADE,
  total INTEGER NOT NULL DEFAULT 0,
  level INTEGER NOT NULL DEFAULT 1,
  today_pp INTEGER NOT NULL DEFAULT 0,
  today_date TEXT,
  version INTEGER NOT NULL DEFAULT 1,
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE preferences (
  child_id TEXT PRIMARY KEY REFERENCES children(id) ON DELETE CASCADE,
  last_session_date TEXT,
  version INTEGER NOT NULL DEFAULT 1,
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE migrations (
  child_id TEXT PRIMARY KEY REFERENCES children(id) ON DELETE CASCADE,
  migrated_at TEXT NOT NULL DEFAULT (datetime('now')),
  source TEXT NOT NULL,
  items_imported INTEGER NOT NULL DEFAULT 0
);
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE processed_operations (
  operation_uuid TEXT PRIMARY KEY,
  child_id TEXT NOT NULL REFERENCES children(id) ON DELETE CASCADE,
  operation_type TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE social_preferences (
  child_id TEXT PRIMARY KEY REFERENCES children(id) ON DELETE CASCADE,
  social_enabled INTEGER NOT NULL DEFAULT 0,
  display_name_visible INTEGER NOT NULL DEFAULT 1,
  pp_visible INTEGER NOT NULL DEFAULT 1,
  avatar_visible INTEGER NOT NULL DEFAULT 1,
  tier_visible INTEGER NOT NULL DEFAULT 1,
  parent_approved_at TEXT,
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE pp_transactions (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  child_id TEXT NOT NULL REFERENCES children(id) ON DELETE CASCADE,
  amount INTEGER NOT NULL,              -- positive = earn, negative = spend
  currency TEXT NOT NULL DEFAULT 'pp',  -- 'pp' or 'rare'
  source TEXT NOT NULL,                 -- e.g. 'correct_answer', 'quiz_completion', 'purchase:basicOutfit'
  context TEXT,                         -- optional JSON: { quizId, topicKey, questionId, itemId, etc. }
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE rare_currency (
  child_id TEXT PRIMARY KEY REFERENCES children(id) ON DELETE CASCADE,
  balance INTEGER NOT NULL DEFAULT 0,
  version INTEGER NOT NULL DEFAULT 1,
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE feature_unlocks (
  child_id TEXT NOT NULL REFERENCES children(id) ON DELETE CASCADE,
  feature_key TEXT NOT NULL,            -- e.g. 'character_creation', 'daily_challenges'
  unlocked_at TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (child_id, feature_key)
);
CREATE TABLE inventory (
  child_id TEXT NOT NULL REFERENCES children(id) ON DELETE CASCADE,
  item_id TEXT NOT NULL,                -- e.g. 'basicOutfit_football_1', 'doubleXPToken'
  quantity INTEGER NOT NULL DEFAULT 1,
  acquired_at TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (child_id, item_id)
);
CREATE TABLE IF NOT EXISTS "children" (
  id TEXT PRIMARY KEY,
  account_id TEXT NOT NULL REFERENCES accounts(id) ON DELETE CASCADE,
  display_name TEXT NOT NULL,
  year_group INTEGER,
  target_school TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
  
);
CREATE TABLE tutors (
  id TEXT PRIMARY KEY,                   
  email TEXT NOT NULL UNIQUE,
  display_name TEXT NOT NULL,
  photo_url TEXT,
  bio TEXT,                              
  tutor_code TEXT NOT NULL UNIQUE,       
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  payout_earned_cents INTEGER NOT NULL DEFAULT 0,
  payout_approved INTEGER NOT NULL DEFAULT 0,      
  bulk_invite_approved INTEGER NOT NULL DEFAULT 0  
);
CREATE TABLE pupil_tutors (
  child_id TEXT NOT NULL REFERENCES children(id) ON DELETE CASCADE,
  tutor_id TEXT NOT NULL REFERENCES tutors(id) ON DELETE CASCADE,
  joined_at TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (child_id, tutor_id)
);
CREATE TABLE classes (
  id TEXT PRIMARY KEY,
  tutor_id TEXT NOT NULL REFERENCES tutors(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  schedule_note TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE class_enrolments (
  class_id TEXT NOT NULL REFERENCES classes(id) ON DELETE CASCADE,
  child_id TEXT NOT NULL REFERENCES children(id) ON DELETE CASCADE,
  enrolled_at TEXT NOT NULL DEFAULT (datetime('now')),
  PRIMARY KEY (class_id, child_id)
);
CREATE TABLE tutor_notes (
  id TEXT PRIMARY KEY,
  tutor_id TEXT NOT NULL,
  child_id TEXT NOT NULL,
  note TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now')),
  
  FOREIGN KEY (child_id, tutor_id) REFERENCES pupil_tutors(child_id, tutor_id) ON DELETE CASCADE
);
CREATE TABLE assignments (
  id TEXT PRIMARY KEY,
  tutor_id TEXT NOT NULL REFERENCES tutors(id) ON DELETE CASCADE,
  target_class_id TEXT,   
  target_child_id TEXT,   
  title TEXT,
  due_date TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  CHECK ((target_class_id IS NULL) != (target_child_id IS NULL)),
  FOREIGN KEY (target_class_id) REFERENCES classes(id) ON DELETE CASCADE,
  
  FOREIGN KEY (target_child_id, tutor_id) REFERENCES pupil_tutors(child_id, tutor_id) ON DELETE CASCADE
);
CREATE TABLE assignment_items (
  id TEXT PRIMARY KEY,
  assignment_id TEXT NOT NULL REFERENCES assignments(id) ON DELETE CASCADE,
  item_type TEXT NOT NULL CHECK (item_type IN ('topic', 'custom_quiz', 'mock', 'lesson')),
  item_ref TEXT NOT NULL,   
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
, subject TEXT);
CREATE TABLE assignment_recipients (
  id TEXT PRIMARY KEY,
  assignment_id TEXT NOT NULL REFERENCES assignments(id) ON DELETE CASCADE,
  assignment_item_id TEXT NOT NULL REFERENCES assignment_items(id) ON DELETE CASCADE,
  child_id TEXT NOT NULL,
  tutor_id TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'assigned'
    CHECK (status IN ('assigned','in_progress','completed','late','cleared','cancelled')),
  assigned_at TEXT NOT NULL DEFAULT (datetime('now')),
  started_at TEXT,
  completed_at TEXT,
  score INTEGER,
  cleared_at TEXT, question_results TEXT,
  
  FOREIGN KEY (child_id, tutor_id) REFERENCES pupil_tutors(child_id, tutor_id) ON DELETE CASCADE,
  UNIQUE (assignment_item_id, child_id)
);
CREATE TABLE conversations (
  id TEXT PRIMARY KEY,
  tutor_id TEXT NOT NULL,
  child_id TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  FOREIGN KEY (child_id, tutor_id) REFERENCES pupil_tutors(child_id, tutor_id) ON DELETE CASCADE,
  UNIQUE (tutor_id, child_id)
);
CREATE TABLE messages (
  id TEXT PRIMARY KEY,
  conversation_id TEXT NOT NULL REFERENCES conversations(id) ON DELETE CASCADE,
  sender_type TEXT NOT NULL CHECK (sender_type IN ('tutor', 'parent')),
  sender_id TEXT NOT NULL,
  body TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  read_at TEXT
);
CREATE TABLE stripe_webhook_events (
  event_id TEXT PRIMARY KEY,
  type TEXT NOT NULL,
  processed_at INTEGER NOT NULL DEFAULT (unixepoch())
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_quiz_results_child ON quiz_results(child_id, completed_at);
CREATE INDEX idx_mock_results_child ON mock_test_results(child_id, completed_at);
CREATE INDEX idx_question_results_child ON question_results(child_id, attempted_at);
CREATE INDEX idx_leitner_child_review ON leitner_queue(child_id, next_review);
CREATE INDEX idx_practice_child_date ON practice_sessions(child_id, session_date);
CREATE INDEX idx_processed_ops_child ON processed_operations(child_id, created_at);
CREATE INDEX idx_processed_ops_created ON processed_operations(created_at);
CREATE INDEX idx_pp_tx_child ON pp_transactions(child_id, created_at);
CREATE INDEX idx_pp_tx_currency ON pp_transactions(child_id, currency);
CREATE INDEX idx_qr_session ON question_results(child_id, session_id);
CREATE INDEX idx_quiz_session ON quiz_results(child_id, session_id);
CREATE INDEX idx_children_account ON children(account_id);
CREATE INDEX idx_tutors_code ON tutors(tutor_code);
CREATE INDEX idx_pupil_tutors_tutor ON pupil_tutors(tutor_id);
CREATE INDEX idx_classes_tutor ON classes(tutor_id);
CREATE INDEX idx_assignments_tutor ON assignments(tutor_id);
CREATE INDEX idx_recipients_child ON assignment_recipients(child_id, tutor_id);
CREATE INDEX idx_messages_conv ON messages(conversation_id, created_at);
CREATE INDEX idx_accounts_stripe_customer
  ON accounts(stripe_customer_id);
CREATE UNIQUE INDEX quiz_results_natural_key
  ON quiz_results (child_id, session_id, topic_key, subject)
  WHERE session_id IS NOT NULL;
CREATE UNIQUE INDEX question_results_natural_key
  ON question_results (child_id, question_id, session_id, topic_key)
  WHERE session_id IS NOT NULL;
CREATE INDEX idx_stripe_webhook_events_type
  ON stripe_webhook_events(type);
